mapper.select:
SELECT r.assignee_name as workerName, r.id as repairNo, r.score, r.comment as evaluation, r.completed_time as completionTime, r.repair_item as repairTitle, CASE WHEN r.score >= 4 THEN '1' WHEN r.score <= 2 THEN '2' ELSE '0' END as rewardType, CASE WHEN r.score >= 4 THEN 100.00 WHEN r.score <= 2 THEN -50.00 ELSE 0.00 END as rewardAmount, CASE WHEN r.score >= 4 THEN '优秀服务奖励' WHEN r.score <= 2 THEN '服务质量待提升' ELSE '正常服务' END as remark FROM sys_property_repair r
r.del_flag = '0' AND r.completed_time IS NOT NULL AND r.score IS NOT NULL
AND r.assignee_name LIKE CONCAT('%', #{workerName}, '%')
AND r.id LIKE CONCAT('%', #{repairNo}, '%')
AND r.completed_time >= #{beginTime}
AND r.completed_time <= #{endTime}
AND r.score = #{score}
ORDER BY r.completed_time DESC

SELECT r.assignee_name as workerName, r.assignee_phone as phoneNumber, COUNT(r.id) as completedCount, ROUND(AVG(r.score), 2) as avgScore, COUNT(CASE WHEN r.score >= 4 THEN 1 END) as rewardCount, COUNT(CASE WHEN r.score <= 2 THEN 1 END) as penaltyCount, SUM(CASE WHEN r.score >= 4 THEN 100 ELSE 0 END) as totalReward, SUM(CASE WHEN r.score <= 2 THEN 50 ELSE 0 END) as totalPenalty, (SUM(CASE WHEN r.score >= 4 THEN 100 ELSE 0 END) - SUM(CASE WHEN r.score <= 2 THEN 50 ELSE 0 END)) as rewardTotal FROM sys_property_repair r WHERE r.del_flag = '0' AND r.completed_time IS NOT NULL AND r.score IS NOT NULL
AND r.completed_time >= #{params.startTime}
AND r.completed_time <= #{params.endTime}
AND r.assignee_name LIKE CONCAT('%', #{params.workerName}, '%')
GROUP BY r.assignee_name, r.assignee_phone ORDER BY avgScore DESC
